const https = require("https");
const START_DATE = "2010-01-01";
const END_DATE = new Date().toISOString().slice(0, 10);
const BATCH_SIZE = 1000;

const TARGET_CURRENCIES = [
  "USD","EUR","GBP","CHF","SEK","NOK","DKK","PLN","CZK","HUF","RON","BGN",
  "RSD","BAM","MKD","TRY","UAH",
  "RUB","BYN","KZT","UZS","KGS","TJS","TMT","AZN","AMD","GEL",
  "AED","SAR","QAR","ILS","OMR","KWD","BHD",
  "CNY","HKD","SGD","JPY","KRW","TWD","INR","THB","MYR","IDR","PHP","VND",
  "CAD","MXN","BRL","CLP","COP","PEN","ARS",
  "ZAR","EGP","MAD"
];

function toCbrDate(iso) {
  const [y, m, d] = iso.split("-");
  return `${d}/${m}/${y}`;
}

function parseNumber(value) {
  return Number(String(value).replace(",", "."));
}

function addDays(isoDate, days) {
  const d = new Date(`${isoDate}T00:00:00Z`);
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString().slice(0, 10);
}

function dateRange(start, end) {
  const result = [];
  let current = start;

  while (current <= end) {
    result.push(current);
    current = addDays(current, 1);
  }

  return result;
}


async function fetchText(url) {
  return await new Promise((resolve, reject) => {
    https
      .get(url, (res) => {
        let data = "";

        if (res.statusCode < 200 || res.statusCode >= 300) {
          reject(new Error(`HTTP ${res.statusCode}: ${url}`));
          res.resume();
          return;
        }

        res.setEncoding("utf8");

        res.on("data", (chunk) => {
          data += chunk;
        });

        res.on("end", () => {
          resolve(data);
        });
      })
      .on("error", reject);
  });
}

function parseCatalog(xml) {
  const rows = [];
  const re = /<Item ID="([^"]+)">([\s\S]*?)<\/Item>/g;

  let m;

  while ((m = re.exec(xml)) !== null) {
    const id = m[1];
    const body = m[2];

    const code = body.match(/<ISO_Char_Code>(.*?)<\/ISO_Char_Code>/)?.[1]?.trim();

    if (code) {
      rows.push({ id, code });
    }
  }

  return rows;
}

function parseHistory(xml) {
  const rows = [];
  const re = /<Record Date="([^"]+)" Id="([^"]+)">([\s\S]*?)<\/Record>/g;

  let m;

  while ((m = re.exec(xml)) !== null) {
    const dateRaw = m[1];
    const body = m[3];

    const nominalRaw = body.match(/<Nominal>(.*?)<\/Nominal>/)?.[1]?.trim();
    const valueRaw = body.match(/<Value>(.*?)<\/Value>/)?.[1]?.trim();

    if (!nominalRaw || !valueRaw) continue;

    const [dd, mm, yyyy] = dateRaw.split(".");
    const rateDate = `${yyyy}-${mm}-${dd}`;

    const nominal = parseNumber(nominalRaw);
    const value = parseNumber(valueRaw);

    if (!nominal || !value) continue;

    rows.push({
      rateDate,
      rubPerUnit: value / nominal,
    });
  }

  return rows;
}

async function fetchHistory(currencyId) {
  const url =
    `https://www.cbr.ru/scripts/XML_dynamic.asp` +
    `?date_req1=${encodeURIComponent(toCbrDate(START_DATE))}` +
    `&date_req2=${encodeURIComponent(toCbrDate(END_DATE))}` +
    `&VAL_NM_RQ=${encodeURIComponent(currencyId)}`;

  return parseHistory(await fetchText(url));
}

const catalogXml = await fetchText("https://www.cbr.ru/scripts/XML_valFull.asp");
const catalog = parseCatalog(catalogXml);
const byCode = new Map(catalog.map((x) => [x.code, x.id]));

const missing = TARGET_CURRENCIES.filter(
  (code) => code !== "RUB" && !byCode.has(code)
);

const histories = new Map();

for (const code of TARGET_CURRENCIES) {
  if (code === "RUB") continue;

  const id = byCode.get(code);
  if (!id) continue;

  const history = await fetchHistory(id);
  histories.set(code, history);
}

const usdHistory = histories.get("USD");

if (!usdHistory || usdHistory.length === 0) {
  throw new Error("USD history not found in CBR");
}

function historyToMap(history) {
  return new Map(history.map((r) => [r.rateDate, r.rubPerUnit]));
}

const historyMaps = new Map();

for (const [code, history] of histories.entries()) {
  historyMaps.set(code, historyToMap(history));
}

const dates = dateRange(START_DATE, END_DATE);
const lastRubPerUnit = new Map();

const rows = [];

for (const rateDate of dates) {
  for (const [code, map] of historyMaps.entries()) {
    if (map.has(rateDate)) {
      lastRubPerUnit.set(code, map.get(rateDate));
    }
  }

  const rubPerUsd = lastRubPerUnit.get("USD");

  if (!rubPerUsd) continue;

  rows.push({
    rate_date: rateDate,
    currency_code: "USD",
    usd_rate: 1,
    source: "CBR"
  });

  rows.push({
    rate_date: rateDate,
    currency_code: "RUB",
    usd_rate: rubPerUsd,
    source: "CBR"
  });

  for (const code of TARGET_CURRENCIES) {
    if (code === "USD" || code === "RUB") continue;

    const rubPerCurrency = lastRubPerUnit.get(code);

    if (!rubPerCurrency) continue;

    rows.push({
      rate_date: rateDate,
      currency_code: code,
      usd_rate: rubPerUsd / rubPerCurrency,
      source: "CBR"
    });
  }
}

const batches = [];

for (let i = 0; i < rows.length; i += BATCH_SIZE) {
  const batch = rows.slice(i, i + BATCH_SIZE);

  batches.push({
    json: {
      batch_no: batches.length + 1,
      batch_size: batch.length,
      missing_in_cbr: missing,
      rowsJson: JSON.stringify(batch)
    }
  });
}

return batches;

const TARGET = [
  "USD","EUR","GBP","CHF","SEK","NOK","DKK",
  "PLN","CZK","HUF","RON","BGN","RSD","BAM",
  "MKD","TRY","UAH","RUB","BYN","KZT","UZS",
  "KGS","TJS","TMT","AZN","AMD","GEL","AED",
  "SAR","QAR","ILS","OMR","KWD","BHD","CNY",
  "HKD","SGD","JPY","KRW","TWD","INR","THB",
  "MYR","IDR","PHP","VND","CAD","MXN","BRL",
  "CLP","COP","PEN","ARS","ZAR","EGP","MAD"
];

const rates = $json.rates || {};

const supported = TARGET.filter(c => rates[c] !== undefined);
const missing = TARGET.filter(c => rates[c] === undefined);

return [{
  json: {
    provider: "open.er-api.com",
    target_count: TARGET.length,
    supported_count: supported.length,
    missing_count: missing.length,
    supported,
    missing
  }
}];
